/* SSRF-Lite static browser — loads data.json generated by generate_ssrf_site.py */
"use strict";

const state = {
  data: null,
  filtered: [],
  sortKey: "freq_mhz",
  sortDir: 1,
  map: null,
  markerLayer: null,
};

const $ = (sel) => document.querySelector(sel);
const esc = (s) =>
  String(s ?? "").replace(/[&<>"']/g, (c) => ({
    "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;",
  })[c]);

function bandOf(freq) {
  if (freq == null) return "";
  if (freq < 30) return "HF";
  if (freq < 54) return "6m";
  if (freq < 148) return "VHF";
  if (freq < 225) return "1.25m";
  if (freq < 512) return "UHF";
  if (freq < 1300) return "23cm";
  return "SHF+";
}

async function init() {
  const resp = await fetch("data.json");
  state.data = await resp.json();

  $("#repo-link").href = state.data.repo;
  $("#footer-repo").href = state.data.repo;
  $("#generated").textContent = `Data generated ${state.data.generated}`;

  populateFilters();
  bindEvents();
  applyFilters();
  renderFiles();
}

function populateFilters() {
  const chans = state.data.channels;
  fillSelect("#filter-service", [...new Set(chans.map((c) => c.service).filter(Boolean))].sort());
  fillSelect("#filter-mode", [...new Set(chans.map((c) => c.mode).filter(Boolean))].sort());
  fillSelect("#filter-band", [...new Set(chans.map((c) => bandOf(c.freq_mhz)).filter(Boolean))]);
  const fileOpts = state.data.files.map((f) => ({ value: f.id, label: f.title }));
  fileOpts.sort((a, b) => a.label.localeCompare(b.label));
  const sel = $("#filter-file");
  for (const o of fileOpts) {
    const opt = document.createElement("option");
    opt.value = o.value;
    opt.textContent = o.label;
    sel.appendChild(opt);
  }
}

function fillSelect(sel, values) {
  const el = $(sel);
  for (const v of values) {
    const opt = document.createElement("option");
    opt.value = v;
    opt.textContent = v;
    el.appendChild(opt);
  }
}

function bindEvents() {
  for (const btn of document.querySelectorAll(".tab")) {
    btn.addEventListener("click", () => switchTab(btn.dataset.tab));
  }
  for (const el of ["#search", "#filter-service", "#filter-mode", "#filter-band", "#filter-file"]) {
    $(el).addEventListener("input", applyFilters);
  }
  for (const th of document.querySelectorAll("th[data-sort]")) {
    th.addEventListener("click", () => {
      const key = th.dataset.sort;
      if (state.sortKey === key) state.sortDir *= -1;
      else { state.sortKey = key; state.sortDir = 1; }
      applyFilters();
    });
  }
}

function switchTab(name) {
  for (const btn of document.querySelectorAll(".tab"))
    btn.classList.toggle("active", btn.dataset.tab === name);
  for (const panel of document.querySelectorAll(".panel"))
    panel.classList.toggle("active", panel.id === `panel-${name}`);
  if (name === "map") initMap();
}

function applyFilters() {
  const q = $("#search").value.trim().toLowerCase();
  const svc = $("#filter-service").value;
  const mode = $("#filter-mode").value;
  const band = $("#filter-band").value;
  const file = $("#filter-file").value;

  state.filtered = state.data.channels.filter((c) => {
    if (svc && c.service !== svc) return false;
    if (mode && c.mode !== mode) return false;
    if (band && bandOf(c.freq_mhz) !== band) return false;
    if (file && c.file !== file) return false;
    if (q) {
      const hay = [
        c.name, c.call_sign, c.org, c.loc_name, c.notes, c.mode,
        c.mode_detail, c.service, c.usage,
        c.freq_mhz != null ? c.freq_mhz.toFixed(4) : "",
      ].join(" ").toLowerCase();
      if (!hay.includes(q)) return false;
    }
    return true;
  });

  const { sortKey, sortDir } = state;
  state.filtered.sort((a, b) => {
    const av = a[sortKey], bv = b[sortKey];
    if (av == null && bv == null) return 0;
    if (av == null) return 1;
    if (bv == null) return -1;
    if (typeof av === "number") return (av - bv) * sortDir;
    return String(av).localeCompare(String(bv)) * sortDir;
  });

  for (const th of document.querySelectorAll("th[data-sort]")) {
    th.classList.toggle("sorted-asc", th.dataset.sort === sortKey && sortDir === 1);
    th.classList.toggle("sorted-desc", th.dataset.sort === sortKey && sortDir === -1);
  }

  $("#result-count").textContent =
    `${state.filtered.length} of ${state.data.channels.length} channels`;

  renderTable();
  if (state.map) renderMarkers();
}

function renderTable() {
  const rows = state.filtered.map((c) => `
    <tr>
      <td>${esc(c.name)}</td>
      <td class="num">${c.freq_mhz != null ? c.freq_mhz.toFixed(4) : ""}</td>
      <td class="num">${c.input_mhz != null ? c.input_mhz.toFixed(4) : ""}</td>
      <td>${esc(c.mode ?? "")}</td>
      <td class="dim">${esc(c.mode_detail ?? "")}</td>
      <td>${c.service ? `<span class="badge">${esc(c.service)}</span>` : ""}</td>
      <td>${esc(c.call_sign ?? "")}</td>
      <td class="dim">${esc(c.loc_name ?? "")}</td>
      <td class="notes">${esc(c.notes ?? "")}</td>
    </tr>`);
  $("#channel-table tbody").innerHTML = rows.join("");
}

function initMap() {
  if (state.map) {
    state.map.invalidateSize();
    return;
  }
  state.map = L.map("map").setView([41.88, -87.63], 8);
  L.tileLayer("https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png", {
    attribution:
      '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> ' +
      'contributors &copy; <a href="https://carto.com/attributions">CARTO</a>',
    maxZoom: 19,
  }).addTo(state.map);
  state.markerLayer = L.layerGroup().addTo(state.map);
  renderMarkers(true);
}

function renderMarkers(fit = false) {
  state.markerLayer.clearLayers();

  // Group filtered channels by coordinate
  const sites = new Map();
  for (const c of state.filtered) {
    if (c.lat == null || c.lon == null) continue;
    const key = `${c.lat},${c.lon}`;
    if (!sites.has(key)) sites.set(key, { lat: c.lat, lon: c.lon, name: c.loc_name, chans: [] });
    sites.get(key).chans.push(c);
  }

  const latlngs = [];
  for (const site of sites.values()) {
    latlngs.push([site.lat, site.lon]);
    const lines = site.chans.slice(0, 12).map((c) =>
      `<div class="popup-chan">${c.freq_mhz != null ? c.freq_mhz.toFixed(4) : "—"} ` +
      `${esc(c.mode ?? "")} — ${esc(c.name)}${c.call_sign ? " (" + esc(c.call_sign) + ")" : ""}</div>`
    );
    if (site.chans.length > 12) lines.push(`<div class="dim">…and ${site.chans.length - 12} more</div>`);
    const marker = L.circleMarker([site.lat, site.lon], {
      radius: 7,
      color: "#4fb3ff",
      weight: 2,
      fillColor: "#4fb3ff",
      fillOpacity: 0.35,
    });
    marker.bindPopup(
      `<div class="popup-title">${esc(site.name ?? "Site")}</div>${lines.join("")}`,
      { maxWidth: 340 }
    );
    state.markerLayer.addLayer(marker);
  }

  if (fit && latlngs.length) {
    state.map.fitBounds(L.latLngBounds(latlngs).pad(0.15));
  }
}

function renderFiles() {
  const byFile = new Map();
  for (const c of state.data.channels) {
    byFile.set(c.file, (byFile.get(c.file) ?? 0) + 1);
  }
  const cards = state.data.files.map((f) => {
    const badges = f.services.map((s) => `<span class="badge">${esc(s)}</span>`).join(" ");
    const srcs = f.sources
      .map((s) => s.url
        ? `<a href="${esc(s.url)}" target="_blank" rel="noopener">${esc(s.name)}</a>`
        : esc(s.name))
      .join(" · ");
    return `
      <div class="card">
        <h3><a href="${esc(f.url)}" target="_blank" rel="noopener">${esc(f.title)}</a></h3>
        <div class="meta">${esc(f.category)} · ${esc(f.region)} · ${byFile.get(f.id) ?? 0} channels</div>
        <div class="badges">${badges}</div>
        ${srcs ? `<div class="src">Sources: ${srcs}</div>` : ""}
      </div>`;
  });
  $("#file-cards").innerHTML = cards.join("");
}

init().catch((err) => {
  document.body.insertAdjacentHTML(
    "beforeend",
    `<p style="padding:1rem;color:#f66">Failed to load data.json — ${esc(err.message)}</p>`
  );
});
